#include <stdio.h>
#define DIM 5

int main() {
    int i, j, red, broj;
    double matrica[DIM][DIM] = {
        {1, 2, 3, 4, 5},
        {6, 7, 8, 9, 9},
        {8, 7, 6, 5, 4},
        {3, 2, 1, 1, 2},
        {3, 4, 5, 6, 7}
    };
    
    printf("Unesite indeks reda koji želite podijeliti (0-%d):\n", DIM-1);
    scanf("%d", &red);
    
    if (red < 0 || red >= DIM) {
        printf("Nevalidan indeks.");
        return 1;
    }
    
    printf("Unesite broj s kojim želite podijeliti red %d:\n", red);
    scanf("%d", &broj);
    
    if (broj <= 0) {
        printf("Nevalidan broj.");
        return 1;
    }
    
    for (j = 0; j < DIM; j++) {
        matrica[red][j] /= broj;
    }
    
    for (i = 0; i < DIM; i++) {
        for (j = 0; j < DIM; j++) {
            printf("%3g ", matrica[i][j]);
        }
        printf("\n");
    }

    return 0;
}
